1	// Edge function: metrics-refresh (US-021)
2	//
3	// Contract:
4	//   POST { social_link_id: string }
5	//     → 200 {
6	//         status: 'queued',
7	//         snapshot_ids: string[],    // empty until the pre-row model lands
8	//         metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status },
9	//       }
10	//       where Status is 'fresh' | 'refreshing' | 'failed'.
11	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
12	//     → 401 { error: 'UNAUTHORIZED' }
13	//     → 403 { error: 'FORBIDDEN' }            // non-creator role
14	//     → 404 { error: 'LINK_NOT_FOUND' }       // social_link_id not owned by caller or missing
15	//     → 422 { error: 'LINK_UNLINKED' }        // the link is in status='unlinked'
16	//     → 429 { error: 'RATE_LIMIT', retry_after_sec: number }
17	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
18	//     → 502 { error: 'APIFY_ERROR' }
19	//
20	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
21	//       _shared/jwt.ts and asserts role='creator'. Deployed with
22	//       verify_jwt=false at the gateway because the gateway only knows
23	//       about Supabase's own JWT secret — the handler enforces auth.
24	//
25	// Throttle: per spec §5.2 / §1.6 a creator may refresh at most once
26	// per 6h per social_link. The throttle is keyed on
27	// `social_links.last_scrape_attempt_at`, which this function bumps to
28	// `now()` BEFORE dispatching Apify so a dispatch failure does not also
29	// reset the throttle (otherwise the creator could burn a scrape, have
30	// it fail, then immediately re-try and double-bill).
31	//
32	// Dispatch: mirrors US-020 (auth-signup-creator). TikTok triggers 1
33	// run (tiktok_profile); Instagram triggers 2 runs (ig_details +
34	// ig_posts). Each run registers a per-run webhook pointing at
35	// /functions/v1/apify-webhook. waitSecs=60 matches the signup path so
36	// the UI can either render 'fresh' immediately or 'refreshing' and
37	// poll. Promise.allSettled — partial failure reports a 'failed' status
38	// for that mode; the creator keeps whatever they already had.
39	//
40	// Spec gap: §5.2 specifies the response as
41	// `{ snapshot_ids, status, retry_after_sec? }` with snapshot_ids
42	// populated by pre-inserting `status='refreshing'` metric_snapshots
43	// rows. US-016..US-020 ship with INSERT + ON CONFLICT DO NOTHING in
44	// the webhook RPCs (no UPDATE-or-INSERT), so pre-rows would leave
45	// permanent `refreshing` rows the webhook can't clear. Once a webhook
46	// RPC story extends each persist_* RPC to UPDATE-or-INSERT, this
47	// function can pre-insert the rows and return real ids. Until then
48	// snapshot_ids is [] and the UI must rely on realtime subscriptions
49	// to metric_snapshots keyed on social_link_id (per US-036).
50	// metrics_status keeps the client informed of the per-mode outcome —
51	// mirrors the US-020 shape so clients can share rendering code.
52	//
53	// Cost/rate: APIFY_KEY + APIFY_WEBHOOK_SECRET must be set. If absent,
54	// returns 500 SERVER_MISCONFIGURED before bumping `last_scrape_attempt_at`
55	// so the throttle is not burned when dispatch isn't possible.
56	
57	import { createClient } from "npm:@supabase/supabase-js@2";
58	import { verifyJwt } from "../_shared/jwt.ts";
59	import { corsHeaders } from "../_shared/cors.ts";
60	import {
61	  type ApifyRunResult,
62	  type ApifyWebhookSpec,
63	  runInstagramDetails,
64	  runInstagramPosts,
65	  runTikTokProfile,
66	} from "../_shared/apify.ts";
67	
68	const THROTTLE_SECS = 6 * 60 * 60;
69	const APIFY_WAIT_SECS = 60;
70	const APIFY_TERMINAL_EVENTS = [
71	  "ACTOR.RUN.SUCCEEDED",
72	  "ACTOR.RUN.FAILED",
73	  "ACTOR.RUN.TIMED_OUT",
74	  "ACTOR.RUN.ABORTED",
75	];
76	const UUID_RE =
77	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
78	
79	type MetricsKey = "tiktok" | "ig_details" | "ig_posts";
80	type MetricsStatus = "fresh" | "refreshing" | "failed";
81	
82	interface RefreshRequest {
83	  social_link_id?: unknown;
84	}
85	
86	interface SocialLinkRow {
87	  id: string;
88	  user_id: string;
89	  platform: "tiktok" | "instagram";
90	  handle: string;
91	  status: string;
92	  last_scrape_attempt_at: string | null;
93	}
94	
95	function jsonResponse(status: number, body: unknown): Response {
96	  return new Response(JSON.stringify(body), {
97	    status,
98	    headers: { ...corsHeaders, "Content-Type": "application/json" },
99	  });
100	}
101	
102	function bearerToken(req: Request): string | null {
103	  const raw = req.headers.get("Authorization") ?? req.headers.get("authorization");
104	  if (!raw) return null;
105	  const m = raw.match(/^Bearer\s+(.+)$/i);
106	  return m ? m[1].trim() : null;
107	}
108	
109	Deno.serve(async (req) => {
110	  if (req.method === "OPTIONS") {
111	    return new Response(null, { status: 204, headers: corsHeaders });
112	  }
113	  if (req.method !== "POST") {
114	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
115	  }
116	
117	  const token = bearerToken(req);
118	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
119	
120	  let claims;
121	  try {
122	    claims = await verifyJwt(token);
123	  } catch {
124	    return jsonResponse(401, { error: "UNAUTHORIZED" });
125	  }
126	  if (claims.role !== "creator") {
127	    return jsonResponse(403, { error: "FORBIDDEN" });
128	  }
129	
130	  let body: RefreshRequest;
131	  try {
132	    body = await req.json();
133	  } catch {
134	    return jsonResponse(400, { error: "INVALID_JSON" });
135	  }
136	
137	  const socialLinkId =
138	    typeof body.social_link_id === "string" &&
139	    UUID_RE.test(body.social_link_id)
140	      ? body.social_link_id
141	      : null;
142	  if (!socialLinkId) {
143	    return jsonResponse(400, { error: "INVALID_REQUEST" });
144	  }
145	
146	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
147	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
148	  const apifyKey = Deno.env.get("APIFY_KEY");
149	  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
150	  if (!supabaseUrl || !serviceRoleKey || !apifyKey || !webhookSecret) {
151	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
152	  }
153	
154	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
155	    auth: { persistSession: false, autoRefreshToken: false },
156	  });
157	
158	  const { data: link, error: linkError } = await supabase
159	    .from("social_links")
160	    .select(
161	      "id,user_id,platform,handle,status,last_scrape_attempt_at",
162	    )
163	    .eq("id", socialLinkId)
164	    .maybeSingle();
165	
166	  if (linkError) {
167	    console.error("social_links lookup failed", linkError);
168	    return jsonResponse(500, { error: "DB_ERROR" });
169	  }
170	  const row = link as SocialLinkRow | null;
171	  if (!row || row.user_id !== claims.sub) {
172	    // 404 rather than 403 so the endpoint doesn't leak which ids exist
173	    // for other creators.
174	    return jsonResponse(404, { error: "LINK_NOT_FOUND" });
175	  }
176	  if (row.status === "unlinked") {
177	    return jsonResponse(422, { error: "LINK_UNLINKED" });
178	  }
179	
180	  // 6h throttle check — keyed on social_links.last_scrape_attempt_at per
181	  // spec §5.2. The check runs before any state mutation, so a throttled
182	  // caller gets a clean 429 with no side effects.
183	  const nowMs = Date.now();
184	  if (row.last_scrape_attempt_at) {
185	    const lastMs = Date.parse(row.last_scrape_attempt_at);
186	    if (Number.isFinite(lastMs)) {
187	      const elapsedSec = Math.floor((nowMs - lastMs) / 1000);
188	      if (elapsedSec < THROTTLE_SECS) {
189	        return jsonResponse(429, {
190	          error: "RATE_LIMIT",
191	          retry_after_sec: THROTTLE_SECS - elapsedSec,
192	        });
193	      }
194	    }
195	  }
196	
197	  // Bump last_scrape_attempt_at BEFORE dispatch so a subsequent failure
198	  // still burns the 6h window — protects Apify budget against a creator
199	  // spamming refresh through a flaky path. If the UPDATE itself fails we
200	  // stop short rather than silently losing the throttle guarantee.
201	  const nowIso = new Date(nowMs).toISOString();
202	  const { error: bumpError } = await supabase
203	    .from("social_links")
204	    .update({ last_scrape_attempt_at: nowIso })
205	    .eq("id", row.id);
206	  if (bumpError) {
207	    console.error("social_links last_scrape_attempt_at bump failed", bumpError);
208	    return jsonResponse(500, { error: "DB_ERROR" });
209	  }
210	
211	  const metricsStatus = await dispatchApifyRuns({
212	    supabaseUrl,
213	    webhookSecret,
214	    link: row,
215	  });
216	
217	  return jsonResponse(200, {
218	    status: "queued",
219	    snapshot_ids: [] as string[],
220	    metrics_status: metricsStatus,
221	  });
222	});
223	
224	async function dispatchApifyRuns(params: {
225	  supabaseUrl: string;
226	  webhookSecret: string;
227	  link: SocialLinkRow;
228	}): Promise<Partial<Record<MetricsKey, MetricsStatus>>> {
229	  const { supabaseUrl, webhookSecret, link } = params;
230	  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};
231	
232	  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
233	  const buildWebhook = (
234	    linkId: string,
235	    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
236	  ): ApifyWebhookSpec => ({
237	    eventTypes: APIFY_TERMINAL_EVENTS,
238	    requestUrl: webhookUrl,
239	    payloadTemplate: JSON.stringify({
240	      eventType: "{{eventType}}",
241	      resource: {
242	        id: "{{resource.id}}",
243	        defaultDatasetId: "{{resource.defaultDatasetId}}",
244	        status: "{{resource.status}}",
245	        actId: "{{resource.actId}}",
246	      },
247	      social_link_id: linkId,
248	      scrape_mode: scrapeMode,
249	      run_id: "{{resource.id}}",
250	      dataset_id: "{{resource.defaultDatasetId}}",
251	    }),
252	    headersTemplate: JSON.stringify({
253	      "X-Apify-Webhook-Secret": webhookSecret,
254	    }),
255	    shouldInterpolateStrings: true,
256	  });
257	
258	  interface Task {
259	    key: MetricsKey;
260	    run: () => Promise<ApifyRunResult>;
261	  }
262	  const tasks: Task[] = [];
263	  if (link.platform === "tiktok") {
264	    tasks.push({
265	      key: "tiktok",
266	      run: () =>
267	        runTikTokProfile(link.handle, {
268	          waitSecs: APIFY_WAIT_SECS,
269	          webhooks: [buildWebhook(link.id, "tiktok_profile")],
270	        }),
271	    });
272	  } else if (link.platform === "instagram") {
273	    tasks.push({
274	      key: "ig_details",
275	      run: () =>
276	        runInstagramDetails(link.handle, {
277	          waitSecs: APIFY_WAIT_SECS,
278	          webhooks: [buildWebhook(link.id, "ig_details")],
279	        }),
280	    });
281	    tasks.push({
282	      key: "ig_posts",
283	      run: () =>
284	        runInstagramPosts(link.handle, {
285	          waitSecs: APIFY_WAIT_SECS,
286	          webhooks: [buildWebhook(link.id, "ig_posts")],
287	        }),
288	    });
289	  }
290	
291	  const settled = await Promise.allSettled(tasks.map((t) => t.run()));
292	  settled.forEach((outcome, i) => {
293	    const key = tasks[i].key;
294	    if (outcome.status === "fulfilled") {
295	      const s = outcome.value.status;
296	      metricsStatus[key] = s === "SUCCEEDED"
297	        ? "fresh"
298	        : s === "READY" || s === "RUNNING" ||
299	            s === "TIMING-OUT" || s === "ABORTING"
300	        ? "refreshing"
301	        : "failed";
302	    } else {
303	      console.error(`apify ${key} dispatch failed`, outcome.reason);
304	      metricsStatus[key] = "failed";
305	    }
306	  });
307	
308	  return metricsStatus;
309	}
