1	// Smoke test for the deployed metrics-refresh edge function (US-021).
2	//
3	// Usage: bun run scripts/test/metrics-refresh.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY always. MARKETIFY_JWT_SECRET
5	// unlocks role + validation + 404 assertions; SUPABASE_SERVICE_ROLE_KEY
6	// unlocks the 429 throttle + 422 unlinked assertions (they need to mutate
7	// the seed social_link). Missing either secret SKIPs the corresponding
8	// assertions with a printed notice rather than failing — the full 10-case
9	// matrix runs in CI where every env var is configured.
10	//
11	// All branches exercised here short-circuit BEFORE the Apify dispatch, so
12	// the test does not burn Apify credits. The happy-path (200 + queued run)
13	// is verified live during mobile-mcp UI verification, not here.
14	//
15	// Asserts:
16	//   1. Missing Authorization → 401 UNAUTHORIZED                                          [always]
17	//   2. Non-Bearer token → 401 UNAUTHORIZED                                               [always]
18	//   3. JWT signed with wrong secret → 401 UNAUTHORIZED                                   [always]
19	//   4. Lister-role JWT → 403 FORBIDDEN                                                   [jwtSecret]
20	//   5. Creator JWT + malformed JSON body → 400 INVALID_JSON                              [jwtSecret]
21	//   6. Creator JWT + missing social_link_id → 400 INVALID_REQUEST                        [jwtSecret]
22	//   7. Creator JWT + non-UUID social_link_id → 400 INVALID_REQUEST                       [jwtSecret]
23	//   8. Creator JWT + UUID not owned by caller → 404 LINK_NOT_FOUND                       [jwtSecret]
24	//   9. Owner JWT + recently-bumped link → 429 RATE_LIMIT with retry_after_sec            [jwtSecret + serviceRole]
25	//  10. Owner JWT + link with status='unlinked' → 422 LINK_UNLINKED                       [jwtSecret + serviceRole]
26	
27	const supabaseUrl = process.env.SUPABASE_URL;
28	const anonKey = process.env.SUPABASE_ANON_KEY;
29	const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
30	const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
31	if (!supabaseUrl || !anonKey) {
32	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
33	  process.exit(1);
34	}
35	if (!jwtSecret) {
36	  console.log(
37	    "MARKETIFY_JWT_SECRET missing — skipping assertions 4–10 (role/validation/404/429/422)",
38	  );
39	}
40	if (!serviceRoleKey) {
41	  console.log(
42	    "SUPABASE_SERVICE_ROLE_KEY missing — skipping assertions 9–10 (throttle/unlinked)",
43	  );
44	}
45	
46	const endpoint = `${supabaseUrl}/functions/v1/metrics-refresh`;
47	
48	// Seeded fixtures from scripts/sql/seed.sql (used by the apify-webhook smoke
49	// test as well). The test mutates last_scrape_attempt_at and status on
50	// these rows and restores them in a finally block.
51	const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
52	const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
53	
54	const encoder = new TextEncoder();
55	
56	function b64url(bytes: Uint8Array): string {
57	  let s = "";
58	  for (const b of bytes) s += String.fromCharCode(b);
59	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
60	}
61	
62	async function signMarketifyJwt(
63	  claims: { sub: string; role: "creator" | "lister"; session_id: string },
64	  secret: string,
65	): Promise<string> {
66	  const now = Math.floor(Date.now() / 1000);
67	  const payload = { ...claims, iat: now, exp: now + 300 };
68	  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
69	  const body = b64url(encoder.encode(JSON.stringify(payload)));
70	  const signingInput = `${header}.${body}`;
71	  const key = await crypto.subtle.importKey(
72	    "raw",
73	    encoder.encode(secret),
74	    { name: "HMAC", hash: "SHA-256" },
75	    false,
76	    ["sign"],
77	  );
78	  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
79	  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
80	}
81	
82	async function post(
83	  bodyValue: string | Record<string, unknown> | null,
84	  authHeader: string | null,
85	) {
86	  const headers: Record<string, string> = {
87	    "Content-Type": "application/json",
88	    apikey: anonKey!,
89	  };
90	  if (authHeader) headers["Authorization"] = authHeader;
91	  const res = await fetch(endpoint, {
92	    method: "POST",
93	    headers,
94	    body: bodyValue == null
95	      ? undefined
96	      : typeof bodyValue === "string"
97	      ? bodyValue
98	      : JSON.stringify(bodyValue),
99	  });
100	  const data = await res.json().catch(() => null);
101	  return { status: res.status, data };
102	}
103	
104	function expect(label: string, cond: boolean, ctx: unknown) {
105	  if (!cond) {
106	    console.error(`FAIL ${label}:`, ctx);
107	    process.exit(1);
108	  }
109	  console.log(`ok — ${label}`);
110	}
111	
112	type SocialLinkStatus = "linked" | "unlinked" | "failed_fetch";
113	
114	async function setLinkFields(
115	  linkId: string,
116	  fields: {
117	    last_scrape_attempt_at?: string | null;
118	    status?: SocialLinkStatus;
119	  },
120	): Promise<void> {
121	  const res = await fetch(
122	    `${supabaseUrl}/rest/v1/social_links?id=eq.${linkId}`,
123	    {
124	      method: "PATCH",
125	      headers: {
126	        apikey: serviceRoleKey!,
127	        Authorization: `Bearer ${serviceRoleKey}`,
128	        "Content-Type": "application/json",
129	        Prefer: "return=minimal",
130	      },
131	      body: JSON.stringify(fields),
132	    },
133	  );
134	  if (!res.ok) {
135	    throw new Error(
136	      `setLinkFields failed: ${res.status} ${await res.text()}`,
137	    );
138	  }
139	}
140	
141	// Snapshot the seed link's current state so we can restore it later.
142	// Only needed when the service role is available (tests 9 and 10 mutate
143	// the link). Without the service role we skip those tests and the
144	// snapshot + restore are no-ops.
145	type LinkSnapshot = {
146	  status: SocialLinkStatus;
147	  last_scrape_attempt_at: string | null;
148	};
149	let snapshot: LinkSnapshot | null = null;
150	if (serviceRoleKey) {
151	  const snapshotRes = await fetch(
152	    `${supabaseUrl}/rest/v1/social_links?id=eq.${SEED_TIKTOK_SOCIAL_LINK_ID}&select=status,last_scrape_attempt_at`,
153	    {
154	      headers: {
155	        apikey: serviceRoleKey,
156	        Authorization: `Bearer ${serviceRoleKey}`,
157	      },
158	    },
159	  );
160	  if (!snapshotRes.ok) {
161	    console.error("seed link snapshot failed:", await snapshotRes.text());
162	    process.exit(1);
163	  }
164	  const [row] = (await snapshotRes.json()) as LinkSnapshot[];
165	  if (!row) {
166	    console.error(
167	      "seed social_link missing — run scripts/sql/seed.sql before this test",
168	    );
169	    process.exit(1);
170	  }
171	  snapshot = row;
172	}
173	
174	let restored = false;
175	async function restore() {
176	  if (restored || !snapshot || !serviceRoleKey) return;
177	  restored = true;
178	  await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, {
179	    status: snapshot.status,
180	    last_scrape_attempt_at: snapshot.last_scrape_attempt_at,
181	  });
182	}
183	
184	try {
185	  // 1. No Authorization header
186	  {
187	    const r = await post({ social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID }, null);
188	    expect(
189	      "missing auth → 401 UNAUTHORIZED",
190	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
191	      r,
192	    );
193	  }
194	
195	  // 2. Non-Bearer scheme
196	  {
197	    const r = await post(
198	      { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
199	      "Basic abcdef",
200	    );
201	    expect(
202	      "non-bearer → 401 UNAUTHORIZED",
203	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
204	      r,
205	    );
206	  }
207	
208	  // 3. JWT signed with wrong secret
209	  {
210	    const badJwt = await signMarketifyJwt(
211	      { sub: SEED_CREATOR_USER_ID, role: "creator", session_id: crypto.randomUUID() },
212	      "wrong-secret-" + Math.random().toString(36).slice(2),
213	    );
214	    const r = await post(
215	      { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
216	      `Bearer ${badJwt}`,
217	    );
218	    expect(
219	      "wrong-secret JWT → 401 UNAUTHORIZED",
220	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
221	      r,
222	    );
223	  }
224	
225	  if (jwtSecret) {
226	    // 4. Lister-role JWT (valid signature, wrong role)
227	    {
228	      const listerJwt = await signMarketifyJwt(
229	        { sub: crypto.randomUUID(), role: "lister", session_id: crypto.randomUUID() },
230	        jwtSecret,
231	      );
232	      const r = await post(
233	        { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
234	        `Bearer ${listerJwt}`,
235	      );
236	      expect(
237	        "lister-role JWT → 403 FORBIDDEN",
238	        r.status === 403 && r.data?.error === "FORBIDDEN",
239	        r,
240	      );
241	    }
242	
243	    // Creator JWT — reused for the remaining validation paths.
244	    const creatorJwt = await signMarketifyJwt(
245	      {
246	        sub: SEED_CREATOR_USER_ID,
247	        role: "creator",
248	        session_id: crypto.randomUUID(),
249	      },
250	      jwtSecret,
251	    );
252	    const creatorAuth = `Bearer ${creatorJwt}`;
253	
254	    // 5. Malformed JSON body
255	    {
256	      const r = await post("{not-json", creatorAuth);
257	      expect(
258	        "malformed JSON → 400 INVALID_JSON",
259	        r.status === 400 && r.data?.error === "INVALID_JSON",
260	        r,
261	      );
262	    }
263	
264	    // 6. Missing social_link_id
265	    {
266	      const r = await post({}, creatorAuth);
267	      expect(
268	        "missing social_link_id → 400 INVALID_REQUEST",
269	        r.status === 400 && r.data?.error === "INVALID_REQUEST",
270	        r,
271	      );
272	    }
273	
274	    // 7. Non-UUID social_link_id
275	    {
276	      const r = await post({ social_link_id: "not-a-uuid" }, creatorAuth);
277	      expect(
278	        "non-UUID social_link_id → 400 INVALID_REQUEST",
279	        r.status === 400 && r.data?.error === "INVALID_REQUEST",
280	        r,
281	      );
282	    }
283	
284	    // 8. Valid UUID that either doesn't exist or isn't owned by caller.
285	    //    Both cases collapse to 404 LINK_NOT_FOUND so the endpoint doesn't
286	    //    leak id existence across creators.
287	    {
288	      const r = await post(
289	        { social_link_id: "00000000-0000-0000-0000-000000000000" },
290	        creatorAuth,
291	      );
292	      expect(
293	        "unknown social_link_id → 404 LINK_NOT_FOUND",
294	        r.status === 404 && r.data?.error === "LINK_NOT_FOUND",
295	        r,
296	      );
297	    }
298	
299	    if (serviceRoleKey) {
300	      // 9. Throttle: bump last_scrape_attempt_at to now and expect 429.
301	      //    This verifies that the 6h window is honoured without burning Apify.
302	      {
303	        const nowIso = new Date().toISOString();
304	        await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, {
305	          last_scrape_attempt_at: nowIso,
306	        });
307	        const r = await post(
308	          { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
309	          creatorAuth,
310	        );
311	        const retryAfter = r.data?.retry_after_sec;
312	        expect(
313	          "recent attempt → 429 RATE_LIMIT with retry_after_sec",
314	          r.status === 429 &&
315	            r.data?.error === "RATE_LIMIT" &&
316	            typeof retryAfter === "number" &&
317	            retryAfter > 0 &&
318	            retryAfter <= 6 * 60 * 60,
319	          r,
320	        );
321	      }
322	
323	      // 10. LINK_UNLINKED: flip status to 'unlinked' and confirm 422.
324	      //     Restore the linked state immediately after — the finally block
325	      //     will also re-apply the original snapshot, but doing it inline
326	      //     keeps the row consistent if later assertions are added.
327	      {
328	        await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, { status: "unlinked" });
329	        const r = await post(
330	          { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
331	          creatorAuth,
332	        );
333	        expect(
334	          "status=unlinked → 422 LINK_UNLINKED",
335	          r.status === 422 && r.data?.error === "LINK_UNLINKED",
336	          r,
337	        );
338	        await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, { status: "linked" });
339	      }
340	    }
341	  }
342	
343	  console.log("all metrics-refresh smoke tests passed");
344	} finally {
345	  await restore();
346	}
